policies.inbound:


    https://catfact.ninja/fact
    GET

<set-variable name="catFact" value="@{
    var response = ((IResponse)context.Variables["catFactResponse"]).Body.As();
    return response["fact"].ToString();
}" />
<set-variable name="catFactLength" value="@{
    var response = ((IResponse)context.Variables["catFactResponse"]).Body.As(preserveContent: true);
    return response["length"].ToString();
}" />

    @((string)context.Variables["catFact"])


    @((string)context.Variables["catFactLength"])
